#include <stdio.h>
#include <conio.h>
#define MAX 5
int stack[MAX], top=-1;
void push()
{
    int x;
    if(top==MAX-1)
        printf("Stack Overflow
");
    else
    {
        printf("Enter element: ");
        scanf("%d", &x);
        stack[++top]=x;
    }
}
void pop()
{
    if(top==-1)
        printf("Stack Underflow
");
    else
        printf("Popped: %d
", stack[top--]);
}
void display()
{
    int i;
    if(top==-1)
        printf("Stack Empty
");
    else
        for(i=top;i>=0;i--)
            printf("%d ", stack[i]);
}
void main()
{
    int ch;
    clrscr();
    while(1)
    {
        printf("
1.Push 2.Pop 3.Display 4.Exit
");
        scanf("%d", &ch);
        switch(ch)
        {
            case 1: push(); break;
            case 2: pop(); break;
            case 3: display(); break;
            case 4: return;
        }
    }
}

#include <stdio.h>
#include <conio.h>
#define MAX 5
int q[MAX], front=-1, rear=-1;
void insert()
{
    int x;
    if(rear==MAX-1)
        printf("Overflow
");
    else
    {
        printf("Enter element: ");
        scanf("%d", &x);
        if(front==-1) front=0;
        q[++rear]=x;
    }
}
void deleteq()
{
    if(front==-1||front>rear)
        printf("Underflow
");
    else
        printf("Deleted: %d
", q[front++]);
}
void display()
{
    int i;
    for(i=front;i<=rear;i++)
        printf("%d ", q[i]);
}
void main()
{
    int ch;
    clrscr();
    while(1)
    {
        printf("
1.Insert 2.Delete 3.Display 4.Exit
");
        scanf("%d", &ch);
        switch(ch)
        {
            case 1: insert(); break;
            case 2: deleteq(); break;
            case 3: display(); break;
            case 4: return;
        }
    }
}

