#include <stdio.h>
#include <conio.h>
#define SIZE 10
void main()
{
    int ht[SIZE],i,key,n,index;
    clrscr();
    for(i=0;i<SIZE;i++) ht[i]=-1;
    printf("Enter number of keys: ");
    scanf("%d", &n);
    for(i=0;i<n;i++)
    {
        scanf("%d", &key);
        index=key%SIZE;
        while(ht[index]!=-1)
            index=(index+1)%SIZE;
        ht[index]=key;
    }
    for(i=0;i<SIZE;i++)
        printf("%d ", ht[i]);
    getch();
}
